'use client'

import Navbar from '@/components/navbar/Navbar'
import Footer from '@/components/sections/Footer'

export default function AboutPage() {
  return (
    <>
      <Navbar />
      <main className="pt-32 pb-16 px-8 bg-branco min-h-screen">
        <div className="max-w-[1200px] mx-auto">
          <h1 className="font-display text-preto text-center mb-20" style={{ fontSize: 'clamp(3rem, 6vw, 5rem)' }}>
            About Babel
          </h1>

          {/* Our Story */}
          <section className="mb-24">
            <h2 className="font-display text-preto text-4xl mb-8">Our Story</h2>
            <p className="text-cinza text-xl leading-relaxed mb-6">
              Babel Designs emerged from a simple observation: true luxury is not found in excess, 
              but in the honest marriage of material and purpose. We design spaces and objects that 
              exist at the intersection of necessity and beauty, where every element justifies its 
              presence through function before form.
            </p>
            <p className="text-cinza text-xl leading-relaxed">
              In a world saturated with ornament masquerading as design, we return to first principles. 
              Our work asks: what remains when everything unnecessary is removed? The answer is not 
              emptiness, but essence—spaces that breathe, materials that age with dignity, and furniture 
              that becomes more meaningful through use.
            </p>
          </section>

          {/* What We Do */}
          <section className="mb-24">
            <h2 className="font-display text-preto text-4xl mb-8">What We Do</h2>
            <p className="text-cinza text-xl leading-relaxed mb-6">
              Babel Designs offers comprehensive interior design services focused on residential and 
              small commercial spaces. Our process begins with understanding how you inhabit space—your 
              routines, your needs, your vision. From there, we develop integrated design systems that 
              blend architecture, furniture, and storage into cohesive environments.
            </p>
            <p className="text-cinza text-xl leading-relaxed">
              We also design custom furniture pieces, each conceived for specific spaces and uses. 
              Currently, fabrication is handled through trusted partnerships, with a long-term vision 
              to bring production in-house, ensuring complete control over quality and execution.
            </p>
          </section>

          {/* Our Approach */}
          <section className="mb-24">
            <h2 className="font-display text-preto text-4xl mb-12">Our Approach</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="border-l-2 border-cinza pl-8">
                <h3 className="font-display text-preto text-2xl mb-4">Integration Over Addition</h3>
                <p className="text-cinza text-lg leading-relaxed">
                  We do not decorate spaces; we design systems where storage, structure, and surface 
                  exist as one. Minimalism achieved through thoughtful integration, not austere elimination.
                </p>
              </div>
              <div className="border-l-2 border-cinza pl-8">
                <h3 className="font-display text-preto text-2xl mb-4">Material Honesty</h3>
                <p className="text-cinza text-lg leading-relaxed">
                  Wood remains wood. Stone remains stone. We select materials for their inherent qualities 
                  and allow them to express their true nature, weathering time with grace rather than fighting it.
                </p>
              </div>
              <div className="border-l-2 border-cinza pl-8">
                <h3 className="font-display text-preto text-2xl mb-4">Functional Restraint</h3>
                <p className="text-cinza text-lg leading-relaxed">
                  Every element must earn its place. If it serves no purpose, it serves no place in our 
                  designs. This discipline creates spaces of remarkable clarity.
                </p>
              </div>
              <div className="border-l-2 border-cinza pl-8">
                <h3 className="font-display text-preto text-2xl mb-4">Timeless Duration</h3>
                <p className="text-cinza text-lg leading-relaxed">
                  We design for decades, not seasons. Our work resists trends in favor of permanence, 
                  creating environments that improve with age and use.
                </p>
              </div>
            </div>
          </section>

          {/* For Whom We Design */}
          <section className="mb-24">
            <h2 className="font-display text-preto text-4xl mb-8">For Whom We Design</h2>
            <p className="text-cinza text-xl leading-relaxed mb-6">
              Our clients value substance over spectacle. They appreciate the difference between true 
              minimalism and empty spaces. They understand that thoughtful design requires investment, 
              but they also recognize that well-designed spaces and objects become more valuable over time.
            </p>
            <p className="text-cinza text-xl leading-relaxed">
              If you seek environments that support life rather than merely showcase it, spaces that 
              reveal their intelligence through use rather than announce it through ostentation, we 
              would welcome the conversation.
            </p>
          </section>

          {/* CTA */}
          <section className="text-center py-16 border-t border-preto/10">
            <h2 className="font-display text-preto text-3xl mb-8">Let's Create Together</h2>
            <a 
              href="/pages/consultancy"
              className="inline-block px-16 py-6 bg-cinza text-branco border-2 border-cinza text-sm tracking-[0.2em] uppercase font-medium hover:bg-transparent hover:text-cinza transition-all duration-400 hover:-translate-y-2"
            >
              Book a Consultation
            </a>
          </section>
        </div>
      </main>
      <Footer />
    </>
  )
}